struct Data {
    id: u32,
    name: String,
}

impl Default for Data {
    fn default() -> Self {
        Data { id: 0, name: String::new() }
    }
}

impl Clone for Data {
    fn clone(&self) -> Self {
        Data {
            id: self.id,
            name: self.name.clone(),
        }
    }
}

fn main() {
    let original = Data::default();
    println!("Original ID: {}", original.id);

    let copy_like = original.clone();
    println!("Copy-like ID: {}", copy_like.id);

    let cloned_name = original.name.clone();
    println!("Cloned Name: {}", cloned_name);
}

