#[derive(Debug, Copy, Clone)]
struct SmallInt(i32);

struct NonCopyWrapper(String);

impl Clone for NonCopyWrapper {
    fn clone(&self) -> Self {
        NonCopyWrapper(self.0.clone())
    }
}

#[derive(Clone)]
struct MixedType {
    id: i32,
    value: SmallInt,
    name: NonCopyWrapper,
}

fn main() {
    let original = MixedType {
        id: 1,
        value: SmallInt(42),
        name: NonCopyWrapper(String::from("Test"))
    };

    let copied_val = original.value;
    let cloned_wrapper = original.name.clone();

    println!("Original ID: {}", original.id);
    println!("Copied Value: {:?}", copied_val);
    println!("Cloned Wrapper: {:?}", cloned_wrapper);

    let original_clone = original.clone();

    println!("Original ID after clone: {}", original_clone.id);
}
